require 'spikard'
require 'json'
require 'faraday'

RSpec.describe 'upload' do
  let(:base_url) { ENV.fetch('TEST_SERVER_URL', 'http://localhost:8080') }
  let(:client) do
    Faraday.new(url: base_url) do |f|
      f.request :json
      f.response :json, content_type: /\bjson$/
    end
  end

  describe 'POST /upload/bytes' do
    it 'Tests file upload read as byte array' do
      response = client.post('/upload/bytes',
        json: { 'file' => { 'content' => 'binary data', 'filename' => 'binary.bin' } },
        headers: { 'Content-Type' => 'multipart/form-data' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'as_bytes' => true, 'filename' => 'binary.bin', 'size' => 11 })
    end
  end

  describe 'POST /upload' do
    it 'Tests basic file upload with single file' do
      response = client.post('/upload',
        json: { 'file' => { 'content' => 'Hello, World!', 'filename' => 'test.txt' } },
        headers: { 'Content-Type' => 'multipart/form-data' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'filename' => 'test.txt', 'size' => 13 })
    end
  end

  describe 'POST /upload/auto-type' do
    it 'Tests file upload uses provided content_type or defaults' do
      response = client.post('/upload/auto-type',
        json: { 'file' => { 'content' => 'Some content', 'filename' => 'unknown.xyz' } },
        headers: { 'Content-Type' => 'multipart/form-data' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'content_type' => 'application/octet-stream', 'filename' => 'unknown.xyz' })
    end
  end

  describe 'POST /upload/string' do
    it 'Tests file upload read as string' do
      response = client.post('/upload/string',
        json: { 'file' => { 'content' => 'Hello, World!', 'filename' => 'text.txt' } },
        headers: { 'Content-Type' => 'multipart/form-data' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'as_string' => true, 'content' => 'Hello, World!', 'filename' => 'text.txt' })
    end
  end

  describe 'POST /upload/typed' do
    it 'Tests file upload preserves custom Content-Type' do
      response = client.post('/upload/typed',
        json: { 'file' => { 'content' => '{"key": "value"}', 'content_type' => 'application/json', 'filename' => 'data.json' } },
        headers: { 'Content-Type' => 'multipart/form-data' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'content_type' => 'application/json', 'filename' => 'data.json', 'size' => 16 })
    end
  end

  describe 'POST /upload/with-fields' do
    it 'Tests file upload with additional form fields' do
      response = client.post('/upload/with-fields',
        json: { 'description' => 'Important document', 'file' => { 'content' => 'PDF content', 'filename' => 'document.pdf' }, 'tags' => ['important', 'archive'] },
        headers: { 'Content-Type' => 'multipart/form-data' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'description' => 'Important document', 'filename' => 'document.pdf', 'tags_count' => 2 })
    end
  end

  describe 'POST /upload/compressed' do
    it 'Tests file upload with gzip content encoding' do
      response = client.post('/upload/compressed',
        json: { 'file' => { 'content' => 'compressed data', 'content_encoding' => 'gzip', 'filename' => 'data.gz' } },
        headers: { 'Content-Type' => 'multipart/form-data' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'content_encoding' => 'gzip', 'filename' => 'data.gz' })
    end
  end

  describe 'POST /upload/multiple' do
    it 'Tests uploading multiple files at once' do
      response = client.post('/upload/multiple',
        json: { 'files' => [{ 'content' => 'Content 1', 'filename' => 'file1.txt' }, { 'content' => 'Content 2', 'filename' => 'file2.txt' }] },
        headers: { 'Content-Type' => 'multipart/form-data' }
      )
      expect(response.status).to eq(200)
      expect(response.body).to eq({ 'total_size' => 18, 'uploaded_files' => 2 })
    end
  end
